A debounce function in JavaScript delays the execution of a provided callback until a specified delay has elapsed since the last time it was invoked, which helps optimize performance for frequent events like user input or scrolling.

```javascript
function debounce(func, delay) {
  let timeoutId;
  return function(...args) {
    clearTimeout(timeoutId);
    timeoutId = setTimeout(() => func.apply(this, args), delay);
  };
}
```

**Example usage:**
```javascript
const logMessage = debounce(() => console.log('Debounced message!'), 300);

// Simulate rapid calls (e.g., on keyup event)
logMessage();
logMessage();
logMessage(); // Only logs once after 300ms of inactivity
```
